const body = $json.body || $json;
const text = typeof body.text === 'string' ? body.text.trim() : '';
const requestId = body.request_id || (globalThis.crypto?.randomUUID ? globalThis.crypto.randomUUID() : `${Date.now()}-${Math.random().toString(36).slice(2,10)}`);
let command = '';
let command_args = '';
if (typeof body.command === 'string' && body.command.trim()) {
  command = body.command.trim().toLowerCase();
  command_args = String(body.command_args || '').trim();
} else if (text.startsWith('/')) {
  const parts = text.split(/\s+/);
  command = parts[0].toLowerCase().replace(/@[^\s]+$/, '');
  command_args = text.slice(parts[0].length).trim();
}
return [{json:{
  request_id: requestId,
  requested_at: new Date().toISOString(),
  tenant_id: body.tenant_id || 'default',
  source: body.source || 'web',
  channel: body.channel || 'web',
  user_id: body.user_id || body.actor_id || 'web-user',
  actor_id: body.actor_id || body.user_id || 'web-user',
  username: body.username || '',
  display_name: body.display_name || body.username || body.actor_id || 'Web User',
  chat_id: body.chat_id || '',
  message_id: body.message_id || '',
  raw_text: text,
  text,
  is_command: command.startsWith('/'),
  command,
  command_args,
  route: command || 'fallback_chat',
  domain: command ? 'phase1' : 'fallback',
  raw_payload: body
}}];

const esc = (s) => String(s ?? '').replace(/'/g, "''");
const j = $json;
return [{json:{
  ...j,
  sql: `INSERT INTO tenants (tenant_id, name) VALUES ('${esc(j.tenant_id)}','${esc(j.tenant_id)}') ON CONFLICT (tenant_id) DO NOTHING;
        INSERT INTO actors (actor_id, tenant_id, username, display_name, source) VALUES ('${esc(j.actor_id)}','${esc(j.tenant_id)}','${esc(j.username)}','${esc(j.display_name)}','${esc(j.source)}')
        ON CONFLICT (actor_id) DO UPDATE SET username=EXCLUDED.username, display_name=EXCLUDED.display_name, updated_at=now();
        SELECT '${esc(j.request_id)}'::text AS request_id, '${esc(j.tenant_id)}'::text AS tenant_id, '${esc(j.actor_id)}'::text AS actor_id,
               '${esc(j.source)}'::text AS source, '${esc(j.channel)}'::text AS channel, '${esc(j.command)}'::text AS command,
               '${esc(j.raw_text)}'::text AS raw_text, '${esc(j.command_args)}'::text AS command_args, '${esc(j.display_name)}'::text AS display_name, '${esc(j.chat_id)}'::text AS chat_id;`
}}];

const esc = (s) => String(s ?? '').replace(/'/g, "''");
const command = $json.command || 'fallback_chat';
const scope = command && command.startsWith('/') ? `command:${command}` : 'command:fallback_chat';
return [{json:{
  ...$json,
  sql: `WITH actor_has_role AS (
          SELECT COUNT(*)::int AS c FROM actor_roles ar WHERE ar.actor_id = '${esc($json.actor_id)}' AND ar.tenant_id='${esc($json.tenant_id)}'
        ),
        allowed AS (
          SELECT EXISTS (
            SELECT 1
            FROM actor_roles ar
            JOIN role_scopes rs ON rs.role_id = ar.role_id
            JOIN scopes s ON s.scope_id = rs.scope_id
            WHERE ar.actor_id='${esc($json.actor_id)}' AND ar.tenant_id='${esc($json.tenant_id)}' AND s.scope_name='${esc(scope)}'
          ) AS via_role,
          (SELECT c FROM actor_has_role) AS role_count
        )
        SELECT '${esc($json.request_id)}'::text AS request_id, '${esc($json.tenant_id)}'::text AS tenant_id, '${esc($json.actor_id)}'::text AS actor_id,
               '${esc($json.source)}'::text AS source, '${esc($json.channel)}'::text AS channel, '${esc($json.command)}'::text AS command,
               '${esc($json.raw_text)}'::text AS raw_text, '${esc($json.command_args)}'::text AS command_args, '${esc($json.display_name)}'::text AS display_name,
               '${esc($json.chat_id)}'::text AS chat_id, '${esc(scope)}'::text AS scope_name,
               CASE WHEN (SELECT via_role FROM allowed) THEN true
                    WHEN (SELECT role_count FROM allowed)=0 AND '${esc(command)}' IN ('','/status','/health','/jobs','/note','/remind','/reminders','/researchnote') THEN true
                    ELSE false END AS allowed;`
}}];

const esc = (s) => String(s ?? '').replace(/'/g, "''");
return [{json:{
  ...$json,
  sql: `INSERT INTO audits (request_id, tenant_id, actor_id, source, channel, route, domain, command, decision, status, started_at)
        VALUES ('${esc($json.request_id)}','${esc($json.tenant_id)}','${esc($json.actor_id)}','${esc($json.source)}','${esc($json.channel)}','${esc($json.route || $json.command || 'fallback_chat')}','${esc($json.domain || 'phase1')}','${esc($json.command)}','pending','started',now())
        ON CONFLICT (request_id) DO UPDATE SET updated_at = now();
        SELECT * FROM (VALUES ('${esc($json.request_id)}','${esc($json.tenant_id)}','${esc($json.actor_id)}','${esc($json.source)}','${esc($json.channel)}','${esc($json.command)}','${esc($json.command_args)}','${esc($json.raw_text)}','${esc($json.display_name)}','${esc($json.chat_id)}', ${$json.allowed ? 'true' : 'false'})) AS t(request_id,tenant_id,actor_id,source,channel,command,command_args,raw_text,display_name,chat_id,allowed);`
}}];

const esc = (s) => String(s ?? '').replace(/'/g, "''");
const j = $json;
if (!j.allowed) {
  return [{json:{...j, action:'invalid', status:'error', error_code:'ACCESS_DENIED', response_text:'Access denied for this command.', response_data:{ok:false,error:{code:'ACCESS_DENIED',message:'Access denied'}}}}];
}
if (!j.command && j.raw_text) {
  return [{json:{...j, action:'service', service_path:'/ai/generate', service_method:'POST', service_body:{tenant_id:j.tenant_id, actor_id:j.actor_id, request_id:j.request_id, prompt:j.raw_text, action_type:'fallback_chat', prompt_version:'phase1.fallback.v1'}, ai_used:true}}];
}
if (j.command === '/health') {
  return [{json:{...j, action:'service', service_path:'/ready', service_method:'GET', ai_used:false}}];
}
if (j.command === '/researchnote') {
  const body = j.command_args || j.raw_text.replace(/^\/researchnote\s*/,'').trim();
  return [{json:{...j, action:'service', service_path:'/ingest/note', service_method:'POST', service_body:{tenant_id:j.tenant_id, actor_id:j.actor_id, title:'Research note', body, metadata:{source:j.source,request_id:j.request_id}}, ai_used:false}}];
}
if (j.command === '/status') {
  return [{json:{...j, action:'sql', sql:`SELECT '${esc(j.request_id)}'::text AS request_id, '${esc(j.tenant_id)}'::text AS tenant_id, '${esc(j.actor_id)}'::text AS actor_id, false AS ai_used,
      (SELECT COUNT(*) FROM notes WHERE tenant_id='${esc(j.tenant_id)}')::int AS notes_count,
      (SELECT COUNT(*) FROM reminders WHERE tenant_id='${esc(j.tenant_id)}' AND status='pending')::int AS pending_reminders,
      (SELECT COUNT(*) FROM jobs WHERE tenant_id='${esc(j.tenant_id)}' AND status IN ('queued','running'))::int AS active_jobs;`, mode:'status'}}];
}
if (j.command === '/jobs') {
  return [{json:{...j, action:'sql', sql:`SELECT job_id::text, job_type, status, priority, retry_count, created_at FROM jobs WHERE tenant_id='${esc(j.tenant_id)}' ORDER BY created_at DESC LIMIT 10;`, mode:'jobs'}}];
}
if (j.command === '/note') {
  const body = j.command_args || j.raw_text.replace(/^\/note\s*/,'').trim();
  if (!body) return [{json:{...j, action:'invalid', status:'error', error_code:'MISSING_ARGUMENT', response_text:'Missing note text.', response_data:{ok:false,error:{code:'MISSING_ARGUMENT',message:'Missing note text'}}}}];
  return [{json:{...j, action:'sql', sql:`INSERT INTO notes (tenant_id, actor_id, body) VALUES ('${esc(j.tenant_id)}','${esc(j.actor_id)}','${esc(body)}') RETURNING note_id::text, body, created_at;`, mode:'note'}}];
}
if (j.command === '/reminders') {
  return [{json:{...j, action:'sql', sql:`SELECT reminder_id::text, task_text, due_at, status, created_at FROM reminders WHERE tenant_id='${esc(j.tenant_id)}' ORDER BY created_at DESC LIMIT 10;`, mode:'reminders'}}];
}
if (j.command === '/remind') {
  const raw = j.command_args || j.raw_text.replace(/^\/remind\s*/,'').trim();
  const parts = raw.split('|');
  const task = (parts[0] || '').trim();
  const due = (parts[1] || '').trim();
  if (!task) return [{json:{...j, action:'invalid', status:'error', error_code:'MISSING_ARGUMENT', response_text:'Missing reminder task.', response_data:{ok:false,error:{code:'MISSING_ARGUMENT',message:'Missing reminder task'}}}}];
  const dueExpr = due ? `'${esc(due)}'::timestamptz` : 'now()';
  return [{json:{...j, action:'sql', sql:`WITH r AS (
      INSERT INTO reminders (tenant_id, actor_id, task_text, due_at) VALUES ('${esc(j.tenant_id)}','${esc(j.actor_id)}','${esc(task)}', ${dueExpr}) RETURNING reminder_id, due_at, task_text
    ), j AS (
      INSERT INTO jobs (tenant_id, actor_id, job_type, status, priority, payload, max_retries, scheduled_at)
      SELECT '${esc(j.tenant_id)}','${esc(j.actor_id)}','deliver_reminder','queued',5,jsonb_build_object('job_type','deliver_reminder','reminder_id', reminder_id::text),3, due_at FROM r RETURNING job_id
    )
    INSERT INTO queue_items (tenant_id, job_id, queue_name, status, priority, schedule_at, available_at, payload, max_retries)
    SELECT '${esc(j.tenant_id)}', j.job_id, 'default','queued',5,r.due_at,r.due_at,jsonb_build_object('job_type','deliver_reminder','reminder_id', r.reminder_id::text),3 FROM r CROSS JOIN j;
    SELECT reminder_id::text, task_text, due_at FROM reminders WHERE tenant_id='${esc(j.tenant_id)}' AND actor_id='${esc(j.actor_id)}' ORDER BY created_at DESC LIMIT 1;`, mode:'remind'}}];
}
return [{json:{...j, action:'invalid', status:'error', error_code:'INVALID_COMMAND', response_text:`Invalid command: ${j.command || ''}`, response_data:{ok:false,error:{code:'INVALID_COMMAND',message:`Invalid command: ${j.command || ''}`}}}}];

const src = $json;
if (src.statusCode && src.statusCode >= 400) {
  const det = src.body?.detail || src.detail || {};
  const code = det.code || 'DOWNSTREAM_FAILURE';
  const msg = det.message || src.message || 'Service request failed';
  return [{json:{...src, final_status:'error', ai_used:false, response_text: msg, response_data:{ok:false, request_id: src.request_id, error:{code, message: msg}}}}];
}
if (src.text) {
  return [{json:{...src, final_status:'ok', ai_used:!!src.ai_used || true, response_text: src.text, response_data:{ok:true, request_id: src.request_id, ai_used:true, model: src.model || null, data:{text: src.text, artifact_id: src.artifact_id || null}}}}];
}
if (src.research_note_id) {
  return [{json:{...src, final_status:'ok', ai_used:false, response_text:`Research note stored (${src.chunks_created} chunks).`, response_data:{ok:true, request_id: src.request_id, ai_used:false, data:{research_note_id: src.research_note_id, chunks_created: src.chunks_created}}}}];
}
if (src.status && src.postgres) {
  return [{json:{...src, final_status:'ok', ai_used:false, response_text:`Health: postgres=${src.postgres}, ollama=${src.ollama}.`, response_data:{ok:true, request_id: src.request_id, ai_used:false, data:src}}}];
}
return [{json:{...src, final_status:'ok', ai_used:false, response_text:'Service request completed.', response_data:{ok:true, request_id: src.request_id, ai_used:false, data:src}}}];

const items = $input.all().map(i => i.json);
const first = items[0] || {};
const mode = $json.mode || first.mode || '';
const base = {...$json};
if (mode === 'status') {
  const row = first;
  return [{json:{...base, final_status:'ok', ai_used:false, response_text:`Status: ${row.notes_count} notes, ${row.pending_reminders} pending reminders, ${row.active_jobs} active jobs.`, response_data:{ok:true, request_id: base.request_id, ai_used:false, data:row}}}];
}
if (mode === 'jobs') {
  const summary = items.length ? items.map(r => `${r.job_type} [${r.status}]`).join('\n') : 'No jobs found.';
  return [{json:{...base, final_status:'ok', ai_used:false, response_text:summary, response_data:{ok:true, request_id: base.request_id, ai_used:false, data:items}}}];
}
if (mode === 'note') {
  return [{json:{...base, final_status:'ok', ai_used:false, response_text:'Note saved.', response_data:{ok:true, request_id: base.request_id, ai_used:false, data:first}}}];
}
if (mode === 'reminders') {
  const summary = items.length ? items.map(r => `• ${r.task_text} (${r.status})`).join('\n') : 'No reminders found.';
  return [{json:{...base, final_status:'ok', ai_used:false, response_text:summary, response_data:{ok:true, request_id: base.request_id, ai_used:false, data:items}}}];
}
if (mode === 'remind') {
  return [{json:{...base, final_status:'ok', ai_used:false, response_text:`Reminder saved: ${first.task_text}`, response_data:{ok:true, request_id: base.request_id, ai_used:false, data:first}}}];
}
return [{json:{...base, final_status:'ok', ai_used:false, response_text:'SQL request completed.', response_data:{ok:true, request_id: base.request_id, ai_used:false, data:items}}}];

const esc = (s) => String(s ?? '').replace(/'/g, "''");
const refs = JSON.stringify($json.response_data?.data || null).replace(/'/g, "''");
return [{json:{
  ...$json,
  sql: `UPDATE audits SET decision='${esc($json.final_status === 'ok' ? 'allow' : 'deny')}', status='${esc($json.final_status === 'ok' ? 'completed' : 'failed')}',
         error_code=${$json.final_status === 'ok' ? 'NULL' : `'${esc($json.error_code || 'DOWNSTREAM_FAILURE')}'`},
         error_message=${$json.final_status === 'ok' ? 'NULL' : `'${esc($json.response_text || '')}'`},
         ai_used=${$json.ai_used ? 'true' : 'false'}, ai_model=${$json.ai_used ? `'${esc($json.model || 'gemma3')}'` : 'NULL'},
         ai_action_type=${$json.ai_used ? `'fallback_chat'` : 'NULL'}, completed_at=now(), grounding_source_refs='${esc(refs)}'::jsonb, updated_at=now()
         WHERE request_id='${esc($json.request_id)}';
         SELECT '${esc($json.request_id)}'::text AS request_id, '${esc($json.response_text || '')}'::text AS response_text;`
}}];
